#include <bits/stdc++.h>
using namespace std;

struct line {
    int x, y, l;
} l[10005];

int n, m, k;
int f[1005];

bool cmp(line x, line y) {
    return x.l < y.l;
}

int find(int x) {
    if (f[x] != x) {
        f[x] = find(f[x]);
    }
    return f[x];
}

int main() {
    cin >> n >> m >> k;
    for (int i = 1; i <= n; i++) f[i] = i;
    for (int i = 0; i < m; i++) {
        cin >> l[i].x >> l[i].y >> l[i].l;
    }
    sort(l, l + m, cmp);
    int ans = 0, cnt = 0;
    for (int i = 0; i < m && cnt < n - k; i++) {
        int x = find(l[i].x);
        int y = find(l[i].y);
        if (x != y) {
            f[x] = y;
            ans += l[i].l;
            cnt++;
        }
    }
    if (cnt < n - k) {
        cout << "No Answer";
    }
    else {
        cout << ans;
    }
    return 0;
}
